def sanitize_log_input(untrusted_input):
    """
    Sanitize user-supplied input before including it in log messages.
    Prevents log injection by:
    1. Removing newline characters (CR, LF) that could forge log entries
    2. Removing other control characters
    3. Truncating excessively long input
    4. Encoding special characters
    """
    if not isinstance(untrusted_input, str):
        untrusted_input = str(untrusted_input)
    
    # Remove carriage returns and newlines to prevent log forging
    sanitized = untrusted_input.replace('\r', '').replace('\n', '')
    
    # Remove other control characters (ASCII 0-31 except tab)
    sanitized = re.sub(r'[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]', '', sanitized)
    
    # Truncate to a reasonable maximum length to prevent log flooding
    max_length = 2048
    if len(sanitized) > max_length:
        sanitized = sanitized[:max_length] + '...[TRUNCATED]'
    
    return sanitized


def validate_log_level(level_str):
    """Validate and return a proper log level."""
    valid_levels = {
        'DEBUG': logging.DEBUG,
        'INFO': logging.INFO,
        'WARNING': logging.WARNING,
        'ERROR': logging.ERROR,
        'CRITICAL': logging.CRITICAL,
    }
    upper_level = level_str.upper() if isinstance(level_str, str) else 'INFO'
    return valid_levels.get(upper_level, logging.INFO)


def validate_service_name(service_name):
    """Validate service name against an allowlist pattern."""
    if not isinstance(service_name, str):
        return 'unknown_service'
    # Only allow alphanumeric, hyphens, underscores, and dots
    if re.match(r'^[a-zA-Z0-9._-]{1,128}$', service_name):
        return service_name
    return 'invalid_service_name'


